 20→#include "pj_bridge/standalone_event_loop.hpp"
 21→
 22→#include <spdlog/spdlog.h>
 23→
 24→#include <atomic>
 25→#include <chrono>
 26→#include <csignal>
 27→#include <thread>
 28→
 29→namespace pj_bridge {
 30→
 31→namespace {
 32→std::atomic<bool> g_shutdown{false};
 33→
 34→void signal_handler(int /*signum*/) {
 35→  g_shutdown.store(true);
 36→}
 37→}  // namespace
 38→
 39→void run_standalone_event_loop(
 40→    BridgeServer& server, std::shared_ptr<SubscriptionManagerInterface> sub_manager,
 41→    std::shared_ptr<WebSocketMiddleware> middleware, const StandaloneConfig& config) {
 42→  std::signal(SIGINT, signal_handler);
 43→  std::signal(SIGTERM, signal_handler);
 44→
 45→  if (!server.initialize()) {
 46→    spdlog::error("Failed to initialize bridge server");
 47→    return;
 48→  }
 49→
 50→  spdlog::info("Bridge server initialized, entering event loop");
 51→
 52→  using clock = std::chrono::steady_clock;
 53→  auto publish_interval =
 54→      std::chrono::duration_cast<std::chrono::nanoseconds>(std::chrono::duration<double>(1.0 / config.publish_rate));
 55→  auto last_publish = clock::now();
 56→  auto last_timeout_check = clock::now();
 57→  auto last_stats_print = clock::now();
 58→
 59→  while (!g_shutdown.load()) {
 60→    server.process_requests();
 61→
 62→    auto now = clock::now();
 63→
 64→    if (now - last_publish >= publish_interval) {
 65→      server.publish_aggregated_messages();
 66→      last_publish += publish_interval;
 67→    }
 68→
 69→    if (now - last_timeout_check >= std::chrono::seconds(1)) {
 70→      server.check_session_timeouts();
 71→      last_timeout_check = now;
 72→    }
 73→
 74→    if (config.stats_enabled && now - last_stats_print >= std::chrono::seconds(5)) {
 75→      auto elapsed = std::chrono::duration<double>(now - last_stats_print).count();
 76→      auto snapshot = server.snapshot_and_reset_stats();
 77→
 78→      std::string stats_msg = "=== Stats ===\n  DDS receive rates:";
 79→      if (snapshot.topic_receive_counts.empty()) {
 80→        stats_msg += "\n    (no subscriptions)";
 81→      } else {
 82→        for (const auto& [topic, count] : snapshot.topic_receive_counts) {
 83→          stats_msg += fmt::format("\n    {}: {:.1f} msg/s", topic, static_cast<double>(count) / elapsed);
 84→        }
 85→      }
 86→
 87→      stats_msg +=
 88→          fmt::format("\n  Publish frequency: {:.1f} Hz", static_cast<double>(snapshot.publish_cycles) / elapsed);
 89→      stats_msg += fmt::format(
 90→          "\n  Sent: {:.2f} MB/s", static_cast<double>(snapshot.total_bytes_published) / elapsed / (1024.0 * 1024.0));
 91→
 92→      spdlog::info(stats_msg);
 93→      last_stats_print = now;
 94→    }
 95→
 96→    std::this_thread::sleep_for(std::chrono::milliseconds(1));
 97→  }
 98→
 99→  spdlog::info("Shutting down...");
100→
101→  // Explicit ordered shutdown to avoid use-after-free:
102→  // 1. Clear DDS message callback
103→  spdlog::debug("[shutdown] Clearing DDS message callback...");
104→  sub_manager->set_message_callback(nullptr);
105→  // 2. Unsubscribe all DDS readers
106→  spdlog::debug("[shutdown] Unsubscribing all DDS readers...");
107→  sub_manager->unsubscribe_all();
108→  // 3. Shutdown WebSocket server
109→  spdlog::debug("[shutdown] Shutting down WebSocket middleware...");
110→  middleware->shutdown();
111→  spdlog::debug("[shutdown] Cleanup complete, exiting scope (destructors will run)...");
112→}
113→
114→}  // namespace pj_bridge
